// after
const HANDLERS:Record<string,(cmd:any)=>unknown> = {a: handleA, b: handleB, ...};
export function handle(cmd:any){
  const h = HANDLERS[cmd.type];
  if (!h) throw new Error(`unknown: ${cmd.type}`);
  return h(cmd);
}

export type ErrorCode = 'INSUFFICIENT_FUNDS' | 'NOT_FOUND' | 'UNAUTHORIZED' | 'INVALID_INPUT';
export class AppError extends Error {
  constructor(public code: ErrorCode, message: string, public details?: unknown) {
    super(message);
  }
}

// usage
throw new AppError('INSUFFICIENT_FUNDS', 'Account balance below transfer amount', {balance, requested});

// error handler
app.use((err, req, res, next) => {
  if (err instanceof AppError) {
    res.status(statusFor(err.code)).json({code: err.code, message: err.message, details: err.details});
  } else {
    res.status(500).json({code: 'INTERNAL', message: 'unexpected'});
  }
});

